sql:
SELECT grade
FROM player_progression
WHERE exp_cumulative = (SELECT MIN(exp_cumulative) FROM player_progression);

SELECT SUM(total_play_time) AS total_play_time_sum
FROM player_game_stats
WHERE game_id = (SELECT game_id FROM games WHERE game_name = 'Battle Arena');

SELECT grade, exp_cumulative AS total_cumulative_exp
FROM player_progression
ORDER BY exp_cumulative DESC;

SELECT grade, exp_required, rank_icon
FROM player_progression
WHERE exp_required > 700000;

SELECT game_id, COUNT(achievement_id) AS achievement_count
FROM mini_achievements
GROUP BY game_id;

external_knowledge:
- "Latest progress" refers to the most recent update based on the created_at timestamp; 
- "Progress in experience points" is determined by subtracting the previous cumulative experience points from the current cumulative experience points; 
- This information is useful for tracking player performance over time.

sql:
SELECT game_id, AVG(exp_required) AS average_exp_required
FROM player_progression
GROUP BY game_id;
